mapper.sql:
instance_id=#{instanceId} AND event_time BETWEEN #{from} AND #{to}
AND source=#{source}
AND category=#{category}
AND category<>'audit'
AND sql_state=#{sqlState}
AND database_name=#{database}
AND user_name=#{user}

  AND (message ILIKE '%'||#{keyword}||'%' OR object_name ILIKE '%'||#{keyword}||'%' OR fingerprint=#{keyword})

instance_id=#{instanceId} AND event_time BETWEEN #{from} AND #{to}
AND collected_at>=now()-INTERVAL '5 minutes'
AND source=#{source}
AND category=#{category}
AND sql_state=#{sqlState}
AND database_name=#{database}
AND user_name=#{user}

  AND (message ILIKE '%'||#{keyword}||'%' OR object_name ILIKE '%'||#{keyword}||'%' OR fingerprint=#{keyword})

mapper.select:
SELECT id,backup_id,target_time,started_at,finished_at,status,validation_result,duration_seconds,
       owner_name,notes,created_at FROM pg_restore_drill
 WHERE instance_id=#{instanceId} ORDER BY started_at DESC LIMIT #{limit} OFFSET #{offset}
